-- Auto-generated by pg_pack (project, project_ut)
-- 2026-03-12

-- Schema: project
CREATE SCHEMA IF NOT EXISTS project;

CREATE OR REPLACE FUNCTION project._avancement_global(p_chantier_id integer)
 RETURNS numeric
 LANGUAGE sql
 STABLE
AS $function$
  SELECT COALESCE(ROUND(AVG(pct_avancement), 1), 0)
  FROM project.jalon
  WHERE chantier_id = p_chantier_id;
$function$;
COMMENT ON FUNCTION project._avancement_global(integer) IS 'Calculate global progress % from milestones';

CREATE OR REPLACE FUNCTION project._client_options()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_html text := '';
  r record;
BEGIN
  FOR r IN SELECT id, name FROM crm.client WHERE active ORDER BY name LOOP
    v_html := v_html || '<option value="' || r.id || '">' || pgv.esc(r.name) || '</option>';
  END LOOP;
  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION project._client_options() IS 'Options HTML des clients actifs pour les selects';

CREATE OR REPLACE FUNCTION project._devis_options(p_client_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_html text := '';
  r record;
BEGIN
  FOR r IN
    SELECT d.id, d.numero, d.objet
      FROM quote.devis d
     WHERE d.statut = 'accepte'
       AND (p_client_id IS NULL OR d.client_id = p_client_id)
     ORDER BY d.created_at DESC
  LOOP
    v_html := v_html || '<option value="' || r.id || '">' || pgv.esc(r.numero || ' — ' || r.objet) || '</option>';
  END LOOP;
  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION project._devis_options(integer) IS 'Options HTML des devis acceptes d''un client';

CREATE OR REPLACE FUNCTION project._next_numero()
 RETURNS text
 LANGUAGE sql
 STABLE
AS $function$
  SELECT 'CHT-' || to_char(now(), 'YYYY') || '-' ||
         lpad((COALESCE(
           (SELECT MAX(substring(numero FROM '\d+$')::int)
            FROM project.chantier
            WHERE numero LIKE 'CHT-' || to_char(now(), 'YYYY') || '-%'),
           0) + 1)::text, 3, '0');
$function$;
COMMENT ON FUNCTION project._next_numero() IS 'Generate next chantier number CHT-YYYY-NNN';

CREATE OR REPLACE FUNCTION project._statut_badge(p_statut text)
 RETURNS text
 LANGUAGE plpgsql
 IMMUTABLE
AS $function$
BEGIN
  RETURN pgv.badge(
    CASE p_statut
      WHEN 'preparation' THEN 'Préparation'
      WHEN 'execution'   THEN 'En cours'
      WHEN 'reception'   THEN 'Réception'
      WHEN 'clos'        THEN 'Clos'
      ELSE initcap(p_statut)
    END,
    CASE p_statut
      WHEN 'preparation' THEN 'warning'
      WHEN 'execution'   THEN 'info'
      WHEN 'reception'   THEN 'success'
      WHEN 'clos'        THEN 'default'
    END
  );
END;
$function$;
COMMENT ON FUNCTION project._statut_badge(text) IS 'Badge colore pour un statut de chantier';

CREATE OR REPLACE FUNCTION project.brand()
 RETURNS text
 LANGUAGE sql
 IMMUTABLE
AS $function$
  SELECT 'Chantiers';
$function$;
COMMENT ON FUNCTION project.brand() IS 'Brand name for Project module';

CREATE OR REPLACE FUNCTION project.chantier_options(p_search text DEFAULT ''::text)
 RETURNS TABLE(value text, label text, detail text)
 LANGUAGE plpgsql
 STABLE
AS $function$
BEGIN
  RETURN QUERY
    SELECT c.id::text,
           c.numero || ' — ' || pgv.esc(c.objet),
           project._statut_badge(c.statut)
      FROM project.chantier c
     WHERE p_search = ''
        OR c.numero ILIKE '%' || p_search || '%'
        OR c.objet  ILIKE '%' || p_search || '%'
     ORDER BY c.updated_at DESC NULLS LAST
     LIMIT 20;
END;
$function$;
COMMENT ON FUNCTION project.chantier_options(text) IS 'Recherche chantiers pour pgv.select_search() — retourne value/label/detail';

CREATE OR REPLACE FUNCTION project.get_chantier(p_id integer)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  c record;
  v_client_name text;
  v_devis_numero text;
  v_body text;
  v_pct numeric;
  v_heures_total numeric;
  v_rows_j text[];
  v_rows_p text[];
  v_rows_n text[];
  v_rows_a text[];
  r record;
  v_has_expense boolean;
  v_total_frais numeric;
  v_expense_rows text[];
BEGIN
  SELECT * INTO c FROM project.chantier WHERE id = p_id;
  IF NOT FOUND THEN RETURN pgv.empty('Chantier introuvable'); END IF;

  SELECT name INTO v_client_name FROM crm.client WHERE id = c.client_id;
  IF c.devis_id IS NOT NULL THEN
    SELECT numero INTO v_devis_numero FROM quote.devis WHERE id = c.devis_id;
  END IF;

  v_pct := project._avancement_global(p_id);

  SELECT COALESCE(sum(heures), 0) INTO v_heures_total
    FROM project.pointage WHERE chantier_id = p_id;

  -- Check if expense module has chantier_id on note (via pg_catalog)
  SELECT EXISTS(
    SELECT 1 FROM pg_catalog.pg_attribute a
      JOIN pg_catalog.pg_class cl ON cl.oid = a.attrelid
      JOIN pg_catalog.pg_namespace ns ON ns.oid = cl.relnamespace
     WHERE ns.nspname = 'expense' AND cl.relname = 'note'
       AND a.attname = 'chantier_id' AND NOT a.attisdropped
  ) INTO v_has_expense;

  -- Fetch expense data if available
  v_total_frais := 0;
  v_expense_rows := ARRAY[]::text[];
  IF v_has_expense THEN
    EXECUTE format(
      'SELECT COALESCE(sum(l.montant_ttc), 0)
         FROM expense.note n JOIN expense.ligne l ON l.note_id = n.id
        WHERE n.chantier_id = %s', p_id
    ) INTO v_total_frais;

    EXECUTE format(
      $q$SELECT array_agg(x ORDER BY x.rn) FROM (
        SELECT row_number() OVER () AS rn,
               format('<a href="/expense/note?p_id=%%s">%%s</a>', n.id, pgv.esc(COALESCE(n.reference, '#' || n.id))),
               pgv.esc(n.auteur),
               to_char(n.date_debut, 'DD/MM/YYYY') || ' → ' || to_char(n.date_fin, 'DD/MM/YYYY'),
               pgv.badge(
                 CASE n.statut WHEN 'brouillon' THEN 'Brouillon' WHEN 'soumise' THEN 'Soumise' WHEN 'validee' THEN 'Validée' WHEN 'refusee' THEN 'Refusée' ELSE n.statut END,
                 CASE n.statut WHEN 'brouillon' THEN 'default' WHEN 'soumise' THEN 'info' WHEN 'validee' THEN 'success' WHEN 'refusee' THEN 'danger' ELSE 'default' END
               ),
               to_char(COALESCE(sum(l.montant_ttc), 0), 'FM999 999.00') || ' €'
          FROM expense.note n
          LEFT JOIN expense.ligne l ON l.note_id = n.id
         WHERE n.chantier_id = %s
         GROUP BY n.id ORDER BY n.date_debut DESC
      ) x$q$, p_id
    ) INTO v_expense_rows;

    IF v_expense_rows IS NULL THEN v_expense_rows := ARRAY[]::text[]; END IF;
  END IF;

  v_body := pgv.breadcrumb(VARIADIC ARRAY[
    'Chantiers', pgv.call_ref('get_chantiers'),
    c.numero
  ]);

  -- Header stats
  v_body := v_body || pgv.grid(VARIADIC ARRAY[
    pgv.stat('Statut', project._statut_badge(c.statut)),
    pgv.stat('Avancement', v_pct::text || ' %'),
    pgv.stat('Heures totales', v_heures_total::text || ' h'),
    pgv.stat('Client', format('<a href="/crm/client?p_id=%s">%s</a>', c.client_id, pgv.esc(v_client_name)))
  ] || CASE WHEN v_has_expense AND v_total_frais > 0
    THEN ARRAY[pgv.stat('Frais', to_char(v_total_frais, 'FM999 999.00') || ' €')]
    ELSE ARRAY[]::text[]
  END);

  -- Info card
  v_body := v_body || pgv.card('Informations',
    pgv.dl(VARIADIC ARRAY[
      'Objet', pgv.esc(c.objet),
      'Adresse', CASE WHEN c.adresse = '' THEN '—' ELSE pgv.esc(c.adresse) END,
      'Devis', CASE WHEN v_devis_numero IS NOT NULL THEN format('<a href="/quote/devis?p_id=%s">%s</a>', c.devis_id, pgv.esc(v_devis_numero)) ELSE '—' END,
      'Début', COALESCE(to_char(c.date_debut, 'DD/MM/YYYY'), '—'),
      'Fin prévue', COALESCE(to_char(c.date_fin_prevue, 'DD/MM/YYYY'), '—'),
      'Fin réelle', COALESCE(to_char(c.date_fin_reelle, 'DD/MM/YYYY'), '—')
    ])
  );

  -- Actions
  v_body := v_body || '<p>';
  IF c.statut = 'preparation' THEN
    v_body := v_body
      || pgv.action('post_chantier_demarrer', 'Démarrer', jsonb_build_object('p_id', p_id), 'Démarrer ce chantier ?')
      || ' '
      || format('<a href="%s" role="button" class="outline">Modifier</a>', pgv.call_ref('get_chantier_form', jsonb_build_object('p_id', p_id)))
      || ' '
      || pgv.action('post_chantier_supprimer', 'Supprimer', jsonb_build_object('p_id', p_id), 'Supprimer ce chantier ?', 'danger');
  ELSIF c.statut = 'execution' THEN
    v_body := v_body
      || pgv.action('post_chantier_reception', 'Passer en réception', jsonb_build_object('p_id', p_id), 'Passer ce chantier en réception ?')
      || ' '
      || format('<a href="%s" role="button" class="outline">Modifier</a>', pgv.call_ref('get_chantier_form', jsonb_build_object('p_id', p_id)));
  ELSIF c.statut = 'reception' THEN
    v_body := v_body
      || pgv.action('post_chantier_clore', 'Clore le chantier', jsonb_build_object('p_id', p_id), 'Clore définitivement ce chantier ?');
  END IF;
  v_body := v_body || '</p>';

  -- Jalons
  v_rows_j := ARRAY[]::text[];
  FOR r IN
    SELECT * FROM project.jalon WHERE chantier_id = p_id ORDER BY sort_order, id
  LOOP
    v_rows_j := v_rows_j || ARRAY[
      r.sort_order::text,
      pgv.esc(r.label),
      pgv.badge(
        CASE r.statut WHEN 'a_faire' THEN 'À faire' WHEN 'en_cours' THEN 'En cours' ELSE 'Validé' END,
        CASE r.statut WHEN 'a_faire' THEN 'default' WHEN 'en_cours' THEN 'info' ELSE 'success' END
      ),
      r.pct_avancement::text || ' %',
      COALESCE(to_char(r.date_prevue, 'DD/MM/YYYY'), '—'),
      CASE WHEN c.statut IN ('preparation','execution') THEN
        pgv.action('post_jalon_avancer', '% ', jsonb_build_object('p_id', r.id, 'p_pct', LEAST(r.pct_avancement + 25, 100)))
        || ' '
        || CASE WHEN r.statut <> 'valide' THEN pgv.action('post_jalon_valider', 'Valider', jsonb_build_object('p_id', r.id), NULL, 'outline') ELSE '' END
        || ' '
        || pgv.action('post_jalon_supprimer', 'X', jsonb_build_object('p_id', r.id), 'Supprimer ce jalon ?', 'danger')
      ELSE '' END
    ];
  END LOOP;

  -- Pointages
  v_rows_p := ARRAY[]::text[];
  FOR r IN
    SELECT * FROM project.pointage WHERE chantier_id = p_id ORDER BY date_pointage DESC, id DESC LIMIT 50
  LOOP
    v_rows_p := v_rows_p || ARRAY[
      to_char(r.date_pointage, 'DD/MM/YYYY'),
      r.heures::text || ' h',
      pgv.esc(r.description),
      CASE WHEN c.statut IN ('preparation','execution') THEN
        pgv.action('post_pointage_supprimer', 'X', jsonb_build_object('p_id', r.id), 'Supprimer ce pointage ?', 'danger')
      ELSE '' END
    ];
  END LOOP;

  -- Notes
  v_rows_n := ARRAY[]::text[];
  FOR r IN
    SELECT * FROM project.note_chantier WHERE chantier_id = p_id ORDER BY created_at DESC LIMIT 50
  LOOP
    v_rows_n := v_rows_n || ARRAY[
      to_char(r.created_at, 'DD/MM/YYYY HH24:MI'),
      pgv.esc(r.contenu),
      CASE WHEN c.statut IN ('preparation','execution') THEN
        pgv.action('post_note_supprimer', 'X', jsonb_build_object('p_id', r.id), 'Supprimer cette note ?', 'danger')
      ELSE '' END
    ];
  END LOOP;

  -- Équipe (affectations)
  v_rows_a := ARRAY[]::text[];
  FOR r IN
    SELECT * FROM project.affectation WHERE chantier_id = p_id ORDER BY id
  LOOP
    v_rows_a := v_rows_a || ARRAY[
      pgv.esc(r.nom_intervenant),
      CASE WHEN r.role = '' THEN '—' ELSE pgv.esc(r.role) END,
      CASE WHEN r.heures_prevues IS NOT NULL THEN r.heures_prevues::text || ' h' ELSE '—' END,
      CASE WHEN c.statut IN ('preparation','execution') THEN
        pgv.action('post_affectation_supprimer', 'X', jsonb_build_object('p_id', r.id), 'Retirer cet intervenant ?', 'danger')
      ELSE '' END
    ];
  END LOOP;

  v_body := v_body || pgv.tabs(VARIADIC ARRAY[
    'Jalons (' || COALESCE(array_length(v_rows_j, 1) / 6, 0) || ')',
    CASE WHEN array_length(v_rows_j, 1) IS NULL
      THEN pgv.empty('Aucun jalon')
      ELSE pgv.md_table(ARRAY['#', 'Jalon', 'Statut', 'Avancement', 'Date prévue', 'Actions'], v_rows_j)
    END
    || CASE WHEN c.statut IN ('preparation','execution') THEN
      '<form data-rpc="post_jalon_ajouter" class="grid">'
      || '<input type="hidden" name="p_chantier_id" value="' || p_id || '">'
      || '<input type="text" name="p_label" placeholder="Nouveau jalon..." required>'
      || '<button type="submit">Ajouter</button>'
      || '</form>'
    ELSE '' END,

    'Équipe (' || COALESCE(array_length(v_rows_a, 1) / 4, 0) || ')',
    CASE WHEN array_length(v_rows_a, 1) IS NULL
      THEN pgv.empty('Aucun intervenant')
      ELSE pgv.md_table(ARRAY['Intervenant', 'Rôle', 'Heures prévues', ''], v_rows_a)
    END
    || CASE WHEN c.statut IN ('preparation','execution') THEN
      '<form data-rpc="post_affectation_ajouter" class="grid">'
      || '<input type="hidden" name="p_chantier_id" value="' || p_id || '">'
      || '<input type="text" name="p_nom_intervenant" placeholder="Nom intervenant" required>'
      || '<input type="text" name="p_role" placeholder="Rôle">'
      || '<input type="number" name="p_heures_prevues" placeholder="Heures" step="0.5" min="0">'
      || '<button type="submit">Ajouter</button>'
      || '</form>'
    ELSE '' END,

    'Pointages (' || COALESCE(array_length(v_rows_p, 1) / 4, 0) || ')',
    CASE WHEN array_length(v_rows_p, 1) IS NULL
      THEN pgv.empty('Aucun pointage')
      ELSE pgv.md_table(ARRAY['Date', 'Heures', 'Description', ''], v_rows_p, 10)
    END
    || CASE WHEN c.statut IN ('preparation','execution') THEN
      '<form data-rpc="post_pointage_ajouter" class="grid">'
      || '<input type="hidden" name="p_chantier_id" value="' || p_id || '">'
      || '<input type="date" name="p_date" value="' || CURRENT_DATE::text || '">'
      || '<input type="number" name="p_heures" placeholder="Heures" step="0.25" min="0.25" required>'
      || '<input type="text" name="p_description" placeholder="Description...">'
      || '<button type="submit">Ajouter</button>'
      || '</form>'
    ELSE '' END,

    'Notes (' || COALESCE(array_length(v_rows_n, 1) / 3, 0) || ')',
    CASE WHEN array_length(v_rows_n, 1) IS NULL
      THEN pgv.empty('Aucune note')
      ELSE pgv.md_table(ARRAY['Date', 'Contenu', ''], v_rows_n, 10)
    END
    || CASE WHEN c.statut IN ('preparation','execution') THEN
      '<form data-rpc="post_note_ajouter">'
      || '<input type="hidden" name="p_chantier_id" value="' || p_id || '">'
      || '<textarea name="p_contenu" placeholder="Nouvelle note..." required></textarea>'
      || '<button type="submit">Ajouter</button>'
      || '</form>'
    ELSE '' END
  ] || CASE WHEN v_has_expense THEN ARRAY[
    'Notes de frais (' || COALESCE(array_length(v_expense_rows, 1) / 5, 0) || ')',
    CASE WHEN array_length(v_expense_rows, 1) IS NULL
      THEN pgv.empty('Aucune note de frais liée')
      ELSE pgv.md_table(ARRAY['Référence', 'Auteur', 'Période', 'Statut', 'Total TTC'], v_expense_rows)
    END
  ] ELSE ARRAY[]::text[] END);

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION project.get_chantier(integer) IS 'Detail chantier : infos, jalons, pointages, notes, equipe, notes de frais (si expense)';

CREATE OR REPLACE FUNCTION project.get_chantier_form(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_body text;
  c record;
  v_objet text := '';
  v_adresse text := '';
  v_notes text := '';
BEGIN
  IF p_id IS NOT NULL THEN
    SELECT * INTO c FROM project.chantier WHERE id = p_id;
    IF NOT FOUND THEN RETURN pgv.empty('Chantier introuvable'); END IF;
    IF c.statut NOT IN ('preparation', 'execution') THEN
      RETURN pgv.empty('Modification impossible', 'Seuls les chantiers en préparation ou en cours sont modifiables.');
    END IF;
    v_objet := pgv.esc(c.objet);
    v_adresse := pgv.esc(c.adresse);
    v_notes := pgv.esc(c.notes);
  END IF;

  v_body := pgv.breadcrumb(VARIADIC ARRAY[
    'Chantiers', pgv.call_ref('get_chantiers'),
    CASE WHEN p_id IS NOT NULL THEN 'Modifier' ELSE 'Nouveau chantier' END
  ]);

  v_body := v_body || '<form data-rpc="post_chantier_save">';
  IF p_id IS NOT NULL THEN
    v_body := v_body || '<input type="hidden" name="id" value="' || p_id || '">';
  END IF;

  v_body := v_body
    || '<label>Client <select name="client_id" required>'
    || '<option value="">— Choisir —</option>'
    || project._client_options()
    || '</select></label>';

  IF p_id IS NOT NULL THEN
    v_body := replace(v_body,
      'value="' || c.client_id || '">',
      'value="' || c.client_id || '" selected>');
  END IF;

  v_body := v_body
    || '<label>Devis lié (optionnel) <select name="devis_id">'
    || '<option value="">— Aucun —</option>'
    || project._devis_options()
    || '</select></label>';

  IF p_id IS NOT NULL AND c.devis_id IS NOT NULL THEN
    v_body := replace(v_body,
      'value="' || c.devis_id || '">',
      'value="' || c.devis_id || '" selected>');
  END IF;

  v_body := v_body
    || '<label>Objet <input type="text" name="objet" value="' || v_objet || '" required></label>'
    || '<label>Adresse <input type="text" name="adresse" value="' || v_adresse || '"></label>'
    || '<div class="grid">'
    || '<label>Date début <input type="date" name="date_debut"'
    || CASE WHEN p_id IS NOT NULL AND c.date_debut IS NOT NULL THEN ' value="' || c.date_debut::text || '"' ELSE '' END
    || '></label>'
    || '<label>Date fin prévue <input type="date" name="date_fin_prevue"'
    || CASE WHEN p_id IS NOT NULL AND c.date_fin_prevue IS NOT NULL THEN ' value="' || c.date_fin_prevue::text || '"' ELSE '' END
    || '></label>'
    || '</div>'
    || '<label>Notes <textarea name="notes">' || v_notes || '</textarea></label>'
    || '<button type="submit">' || CASE WHEN p_id IS NOT NULL THEN 'Mettre à jour' ELSE 'Créer le chantier' END || '</button>'
    || '</form>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION project.get_chantier_form(integer) IS 'Formulaire creation/edition chantier';

CREATE OR REPLACE FUNCTION project.get_chantiers(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_statut text := p_params->>'statut';
  v_q      text := p_params->>'q';
  v_body   text;
  v_rows   text[];
  r        record;
BEGIN
  -- Formulaire de filtre
  v_body := format(
    '<form method="get" action="%s" class="grid">'
    || '<label>Statut<select name="statut">'
    || '<option value="">Tous</option>'
    || '<option value="preparation"%s>Préparation</option>'
    || '<option value="execution"%s>En cours</option>'
    || '<option value="reception"%s>Réception</option>'
    || '<option value="clos"%s>Clos</option>'
    || '</select></label>'
    || '<label>Recherche<input type="search" name="q" value="%s" placeholder="Numéro, client, objet…"></label>'
    || '<button type="submit">Filtrer</button>'
    || '</form>',
    pgv.call_ref('get_chantiers'),
    CASE WHEN v_statut = 'preparation' THEN ' selected' ELSE '' END,
    CASE WHEN v_statut = 'execution'   THEN ' selected' ELSE '' END,
    CASE WHEN v_statut = 'reception'   THEN ' selected' ELSE '' END,
    CASE WHEN v_statut = 'clos'        THEN ' selected' ELSE '' END,
    pgv.esc(COALESCE(v_q, ''))
  );

  -- Requête filtrée
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT c.id, c.client_id, c.devis_id, c.numero, cl.name AS client, c.objet, c.statut,
           project._avancement_global(c.id) AS pct,
           c.date_debut, d.numero AS devis_numero
      FROM project.chantier c
      JOIN crm.client cl ON cl.id = c.client_id
      LEFT JOIN quote.devis d ON d.id = c.devis_id
     WHERE (v_statut IS NULL OR v_statut = '' OR c.statut = v_statut)
       AND (v_q IS NULL OR v_q = ''
            OR c.numero ILIKE '%' || v_q || '%'
            OR cl.name  ILIKE '%' || v_q || '%'
            OR c.objet  ILIKE '%' || v_q || '%')
     ORDER BY c.updated_at DESC
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_chantier', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero)),
      format('<a href="/crm/client?p_id=%s">%s</a>', r.client_id, pgv.esc(r.client)),
      pgv.esc(r.objet),
      project._statut_badge(r.statut),
      pgv.badge(r.pct::text || ' %'),
      CASE WHEN r.devis_numero IS NOT NULL
        THEN format('<a href="/quote/devis?p_id=%s">%s</a>', r.devis_id, pgv.esc(r.devis_numero))
        ELSE '—' END,
      COALESCE(to_char(r.date_debut, 'DD/MM/YYYY'), '—')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucun chantier trouvé', 'Essayez de modifier vos filtres.');
  ELSE
    v_body := v_body || pgv.md_table(
      ARRAY['Numéro', 'Client', 'Objet', 'Statut', 'Avancement', 'Devis', 'Début'],
      v_rows, 15
    );
  END IF;

  v_body := v_body || '<p>'
    || format('<a href="%s" role="button">Nouveau chantier</a>', pgv.call_ref('get_chantier_form'))
    || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION project.get_chantiers(jsonb) IS 'Liste des chantiers avec filtres statut et recherche texte';

CREATE OR REPLACE FUNCTION project.get_index()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_en_cours int;
  v_preparation int;
  v_clos_mois int;
  v_heures_semaine numeric;
  v_body text;
  v_rows text[];
  v_alert_rows text[];
  r record;
BEGIN
  SELECT count(*)::int INTO v_en_cours
    FROM project.chantier WHERE statut = 'execution';

  SELECT count(*)::int INTO v_preparation
    FROM project.chantier WHERE statut = 'preparation';

  SELECT count(*)::int INTO v_clos_mois
    FROM project.chantier
   WHERE statut = 'clos'
     AND date_fin_reelle >= date_trunc('month', CURRENT_DATE);

  SELECT COALESCE(sum(heures), 0) INTO v_heures_semaine
    FROM project.pointage
   WHERE date_pointage >= date_trunc('week', CURRENT_DATE);

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('En cours', v_en_cours::text),
    pgv.stat('En préparation', v_preparation::text),
    pgv.stat('Terminés ce mois', v_clos_mois::text),
    pgv.stat('Heures semaine', v_heures_semaine::text || ' h')
  ]);

  -- Alertes retard
  v_alert_rows := ARRAY[]::text[];
  FOR r IN
    SELECT c.id, c.numero, cl.name AS client, c.objet,
           project._statut_badge(c.statut) AS statut_badge,
           (CURRENT_DATE - c.date_fin_prevue) AS jours_retard
      FROM project.chantier c
      JOIN crm.client cl ON cl.id = c.client_id
     WHERE c.date_fin_prevue < CURRENT_DATE
       AND c.statut NOT IN ('clos', 'reception')
     ORDER BY c.date_fin_prevue ASC
  LOOP
    v_alert_rows := v_alert_rows || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_chantier', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero)),
      pgv.esc(r.client),
      pgv.esc(r.objet),
      r.statut_badge,
      pgv.badge(r.jours_retard::text || ' j', 'warning')
    ];
  END LOOP;

  IF array_length(v_alert_rows, 1) IS NOT NULL THEN
    v_body := v_body || '<h3>Alertes retard</h3>'
      || pgv.md_table(
        ARRAY['Numéro', 'Client', 'Objet', 'Statut', 'Retard'],
        v_alert_rows
      );
  END IF;

  -- Liste chantiers actifs
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT c.id, c.client_id, c.devis_id, c.numero, cl.name AS client, c.objet, c.statut,
           project._avancement_global(c.id) AS pct,
           c.date_debut, d.numero AS devis_numero
      FROM project.chantier c
      JOIN crm.client cl ON cl.id = c.client_id
      LEFT JOIN quote.devis d ON d.id = c.devis_id
     WHERE c.statut IN ('preparation', 'execution', 'reception')
     ORDER BY c.updated_at DESC
     LIMIT 20
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_chantier', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero)),
      format('<a href="/crm/client?p_id=%s">%s</a>', r.client_id, pgv.esc(r.client)),
      pgv.esc(r.objet),
      project._statut_badge(r.statut),
      pgv.badge(r.pct::text || ' %'),
      CASE WHEN r.devis_numero IS NOT NULL
        THEN format('<a href="/quote/devis?p_id=%s">%s</a>', r.devis_id, pgv.esc(r.devis_numero))
        ELSE '—' END,
      COALESCE(to_char(r.date_debut, 'DD/MM/YYYY'), '—')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucun chantier actif', 'Créez votre premier chantier pour commencer.');
  ELSE
    v_body := v_body || '<h3>Chantiers actifs</h3>'
      || pgv.md_table(
        ARRAY['Numéro', 'Client', 'Objet', 'Statut', 'Avancement', 'Devis', 'Début'],
        v_rows, 10
      );
  END IF;

  v_body := v_body || '<p>'
    || format('<a href="%s" role="button">Nouveau chantier</a>', pgv.call_ref('get_chantier_form'))
    || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION project.get_index() IS 'Dashboard chantiers : stats KPI + alertes retard + liste chantiers actifs';

CREATE OR REPLACE FUNCTION project.get_planning()
 RETURNS text
 LANGUAGE plpgsql
 STABLE
AS $function$
DECLARE
  v_body text;
  v_rows text[];
  r record;
BEGIN
  v_body := '<h3>Planning des chantiers actifs</h3>';

  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT c.id, c.numero, cl.name AS client, c.objet,
           project._statut_badge(c.statut) AS statut_badge,
           project._avancement_global(c.id) AS pct,
           c.date_debut, c.date_fin_prevue,
           (SELECT string_agg(
              j.label || ' ' || pgv.badge(
                CASE j.statut WHEN 'valide' THEN '✓' WHEN 'en_cours' THEN j.pct_avancement::text || '%' ELSE '—' END,
                CASE j.statut WHEN 'valide' THEN 'success' WHEN 'en_cours' THEN 'info' ELSE 'default' END
              ), ' '
              ORDER BY j.sort_order
            ) FROM project.jalon j WHERE j.chantier_id = c.id
           ) AS jalons_resume,
           (SELECT count(*)::int FROM project.affectation a WHERE a.chantier_id = c.id) AS nb_intervenants
      FROM project.chantier c
      JOIN crm.client cl ON cl.id = c.client_id
     WHERE c.statut IN ('preparation', 'execution', 'reception')
     ORDER BY c.date_debut NULLS LAST, c.numero
  LOOP
    v_rows := v_rows || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_chantier', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero)),
      pgv.esc(r.client),
      r.statut_badge,
      pgv.badge(r.pct::text || ' %'),
      COALESCE(to_char(r.date_debut, 'DD/MM'), '—') || ' → ' || COALESCE(to_char(r.date_fin_prevue, 'DD/MM'), '—'),
      r.nb_intervenants::text,
      COALESCE(r.jalons_resume, '—')
    ];
  END LOOP;

  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucun chantier actif');
  ELSE
    v_body := v_body || pgv.md_table(
      ARRAY['Chantier', 'Client', 'Statut', 'Avancement', 'Période', 'Équipe', 'Jalons'],
      v_rows
    );
  END IF;

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION project.get_planning() IS 'Vue planning : chantiers actifs avec jalons et dates';

